// // This comment suggests that the flip-flop captures the input data on the falling edge of the clock when reset is not asserted.
module d_flip_flop (
    input clk,
    input reset,
    input d,
    output reg q);always @(posedge clk or posedge reset) begin
    if (reset) q <= 1'b0;
    else q <= d;
end
endmodule
